import React from 'react';

const entries = [
  {
    degree: 'Bachelor of Science in Information Technology',
    major: 'Major in Web Technology',
    school: 'Your University Name',
    year: '2023 – Present',
    sym: '△',
    color: '#7be8b4',
  },
  {
    degree: 'Senior High School',
    major: 'STEM / ICT Track',
    school: 'Your Senior High School',
    year: '2021 – 2023',
    sym: '□',
    color: '#e87bce',
  },
];

const Education = () => (
  <section
    id="Education"
    className="min-h-screen flex flex-col justify-center items-center px-5 py-24"
    style={{ background: 'var(--ps-dark, #00052b)' }}
  >
    <h1 className="ps-title font-bold text-4xl text-white text-center mb-12">Education</h1>

    <div className="w-full max-w-2xl flex flex-col gap-5">
      {entries.map((e, i) => (
        <div
          key={i}
          className="rounded-xl p-6 transition-transform duration-300 hover:-translate-y-1"
          style={{
            background: 'rgba(0,55,145,0.15)',
            border: `1px solid ${e.color}55`,
            borderLeft: `3px solid ${e.color}`,
          }}
        >
          {/* PS symbol badge */}
          <div className="flex items-center gap-3 mb-2">
            <span
              style={{
                display: 'inline-flex',
                alignItems: 'center',
                justifyContent: 'center',
                width: '28px',
                height: '28px',
                borderRadius: '50%',
                border: `1.5px solid ${e.color}`,
                color: e.color,
                fontSize: '13px',
                flexShrink: 0,
              }}
            >
              {e.sym}
            </span>
            <h3 className="font-bold text-base" style={{ color: e.color }}>{e.degree}</h3>
          </div>
          <p className="italic text-sm mt-1" style={{ color: 'rgba(255,255,255,0.55)' }}>{e.major}</p>
          <p className="text-white mt-2 text-sm">{e.school}</p>
          <p className="text-xs mt-1" style={{ color: 'rgba(255,255,255,0.4)' }}>{e.year}</p>
        </div>
      ))}
    </div>
  </section>
);

export default Education;
